// ─── VITALS-BASED RISK SCORE LOGIC ──────────────────────────
// Input shape: { data: "<FHIR Bundle as string>" }

const input = $input.first().json || {};

let bundle = {};
try {
  bundle = typeof input.data === 'string' ? JSON.parse(input.data) : (input.data || input);
} catch (err) {
  return [{
    json: {
      cards: [{
        summary: 'Risk score unavailable',
        indicator: 'warning',
        detail: `Could not parse vitals bundle: ${err.message}`,
        source: { label: 'n8n Risk Score Plugin' }
      }]
    }
  }];
}

const entries = bundle.entry?.map(e => e.resource) ?? [];

if (!Array.isArray(entries) || entries.length === 0) {
  return [{
    json: {
      cards: [{
        summary: 'Risk score unavailable',
        indicator: 'warning',
        detail: 'No vital sign observations were found for this patient.',
        source: { label: 'n8n Risk Score Plugin' }
      }]
    }
  }];
}

let score = 0;
const flags = [];

for (const obs of entries) {
  const name = (obs.code?.text || obs.code?.coding?.[0]?.display || '').toLowerCase();

  // Standard single-value observations
  const value = obs.valueQuantity?.value;

  if (value !== undefined && value !== null) {
    // Weight
    if (name.includes('body weight') || name.includes('weight')) {
      if (value > 5) {
        score += 1;
        flags.push(`Higher weight marker (${value.toFixed(1)} kg)`);
      }
    }

    // Pain score
    if (name.includes('pain severity') || name.includes('pain')) {
      if (value >= 4) {
        score += 1;
        flags.push(`Pain score elevated (${value.toFixed(1)})`);
      }
    }
  }

  // Blood pressure in component array
  if (Array.isArray(obs.component)) {
    for (const comp of obs.component) {
      const compName = (comp.code?.text || comp.code?.coding?.[0]?.display || '').toLowerCase();
      const compValue = comp.valueQuantity?.value;

      if (compValue === undefined || compValue === null) continue;

      if (compName.includes('systolic')) {
        if (compValue > 110) {
          score += 1;
          flags.push(`Systolic BP elevated (${compValue.toFixed(1)} mmHg)`);
        } else if (compValue < 90) {
          score += 2;
          flags.push(`Systolic BP low (${compValue.toFixed(1)} mmHg)`);
        }
      }

      if (compName.includes('diastolic')) {
        if (compValue > 80) {
          score += 1;
          flags.push(`Diastolic BP elevated (${compValue.toFixed(1)} mmHg)`);
        } else if (compValue < 60) {
          score += 1;
          flags.push(`Diastolic BP low (${compValue.toFixed(1)} mmHg)`);
        }
      }
    }
  }
}

const level = score >= 4 ? 'warning' : 'info';
const label = score >= 4 ? 'MODERATE CONCERN' : score > 0 ? 'LOW CONCERN' : 'NO CONCERN';
const detail = flags.length
  ? `Findings detected: ${flags.join('; ')}`
  : 'No configured abnormalities were detected in the returned vital signs.';

return [{
  json: {
    cards: [{
      summary: `${label} — Risk Score: ${score}`,
      indicator: level,
      detail,
      source: { label: 'n8n Risk Score Plugin' }
    }]
  }
}];

// ─── CARE GAPS LOGIC ───────────────────────────────────────
// Input shape here is: { data: "<FHIR Bundle as string>" }

const input = $input.first().json || {};

let bundle = {};
try {
  bundle = typeof input.data === 'string' ? JSON.parse(input.data) : (input.data || input);
} catch (err) {
  return [{
    json: {
      table: {
        headers: ['Debug', 'Status', 'Details'],
        rows: [[
          'Bundle Parse',
          'Failed',
          `Could not parse input.data: ${err.message}`
        ]]
      }
    }
  }];
}

const imms = bundle.entry?.map(e => e.resource) ?? [];

if (!Array.isArray(imms) || imms.length === 0) {
  return [{
    json: {
      table: {
        headers: ['Debug', 'Status', 'Details'],
        rows: [[
          'Immunization Fetch',
          'No records found',
          `Bundle keys: ${Object.keys(bundle).join(', ')}`
        ]]
      }
    }
  }];
}

// Normalize vaccine names from both text and coding.display
const receivedTexts = imms
  .flatMap(i => [
    i.vaccineCode?.text || '',
    ...(i.vaccineCode?.coding?.map(c => c.display || '') || [])
  ])
  .map(s => s.toLowerCase().trim())
  .filter(Boolean);

// Helper matcher
const hasMatch = (keywords) =>
  receivedTexts.some(text => keywords.some(k => text.includes(k)));

const standard = [
  {
    name: 'Influenza',
    keywords: ['influenza', 'flu']
  },
  {
    name: 'Pneumococcal',
    keywords: ['pneumococcal', 'pcv', 'pneumo']
  },
  {
    name: 'Tdap / DTaP',
    keywords: ['tdap', 'dtap']
  },
  {
    name: 'COVID-19',
    keywords: ['covid']
  },
  {
    name: 'Hepatitis B',
    keywords: ['hepatitis b', 'hep b']
  }
];

const headers = ['Vaccine', 'Status', 'Recommended Action'];
const rows = [];

for (const vaccine of standard) {
  const present = hasMatch(vaccine.keywords);

  rows.push([
    vaccine.name,
    present ? '✓ On record' : '⚠ Not on record',
    present ? 'No action needed' : 'Review and offer if eligible'
  ]);
}

return [{
  json: {
    table: {
      headers,
      rows
    }
  }
}];
